import{k as r,r as u,l as _,s as m,u as f,q as l,x as e,v as n,O as v,A as p,N as y,V as C,C as k,D as g,E as b}from"./vue-vendor-a6fe6a19.js";import{u as x}from"./spatiotemporal-b82dde4d.js";import{_ as M}from"./PageShell.vue_vue_type_script_setup_true_lang-5f25b3a8.js";import{_ as S}from"./index-407e3d7c.js";import"./pinia-79250736.js";import"./HeaderPanel-d23c6e02.js";const w=a=>(g("data-v-9817dcdf"),a=a(),b(),a),B={class:"culture-categories"},I=["onClick"],L={class:"glyph-mark"},N=w(()=>e("span",{class:"read-more"},"阅读详情",-1)),P=["onClick"],V={class:"modal-content ui-panel"},D={class:"modal-header"},E={class:"glyph-mark"},H=["innerHTML"],T=r({__name:"CulturePage",setup(a){const o=x(),t=u(null),c=[{id:1,title:"桥梁与建筑技术",icon:"技",summary:"从敞肩拱到种蛎固基，中国古代桥梁凝聚了工匠的结构智慧与材料工艺。",detail:`
      <h4>赵州桥：敞肩拱结构的典范</h4>
      <p>赵州桥位于河北赵县，建于隋朝大业年间（公元605-618年），由工匠李春设计建造。它是世界上现存最早、保存最完好的敞肩石拱桥，全长50.82米，宽9.6米，主拱跨径37.37米。其敞肩拱设计减轻了桥身重量，增强了泄洪能力，开创了桥梁建筑的新纪元。1961年被国务院列为第一批全国重点文物保护单位。著名桥梁专家茅以升曾赞誉赵州桥为"世界土木工程史上的奇迹"。</p>
      <h4>洛阳桥：海港石桥的开创者</h4>
      <p>洛阳桥位于福建泉州，始建于北宋皇祐五年（1053年），历时六年建成。桥梁全长834米，宽7米，采用筏形基础和种蛎固基法，开创了建造海港石桥的先河。"蛎房"加固地基的技术是世界桥梁史上的创举，比西方类似技术早数百年。洛阳桥是中国现存最早的跨海梁式石桥，被誉为"海内第一桥"。</p>
      <h4>卢沟桥：联拱石桥的杰作</h4>
      <p>卢沟桥位于北京，始建于金大定二十九年（1189年），全长266.5米，宽7.5米，共有11个拱洞。桥两侧栏杆上雕刻有485只石狮，形态各异，栩栩如生，是中国古代雕刻艺术的珍品。1937年"七七事变"在此爆发，使其成为中华民族抗日战争的重要纪念地。马可·波罗在其游记中曾盛赞卢沟桥的壮丽。</p>
      <h4>安平桥：天下无桥长此桥</h4>
      <p>安平桥位于福建晋江，始建于南宋绍兴八年（1138年），全长2255米，是中国现存最长的古代石桥，享有"天下无桥长此桥"的美誉。桥梁采用花岗岩建造，结构坚固，至今仍在使用。桥上有五座方形石塔和一座圆塔，造型独特。</p>
      <h4>广济桥：世界最早的启闭式桥梁</h4>
      <p>广济桥位于广东潮州，始建于南宋乾道七年（1171年），全长518米。其独特的"十八梭船廿四洲"结构是世界上最早的启闭式桥梁，白天开启便于通航，晚上闭合方便行人通行。桥上有众多亭台楼阁，被誉为"世界上最早的活动式桥梁"。</p>
      <h4>五亭桥：中国最美的桥梁</h4>
      <p>五亭桥位于江苏扬州瘦西湖，建于清乾隆二十二年（1757年）。桥梁造型独特，桥上建有五座亭子，造型秀丽，被誉为"中国最美的桥梁"。其设计巧妙，兼具实用性和艺术性，是江南园林桥梁的代表作。</p>
    `},{id:2,title:"桥梁历史演变",icon:"史",summary:"从先秦木石桥到明清石拱桥，桥梁形态随朝代更迭而演进。",detail:`
      <h4>先秦时期：原始桥梁的诞生</h4>
      <p>早在新石器时代，先民们就用树木、石块搭建简易桥梁。商周时期出现了梁桥和浮桥，《诗经·大雅·大明》中已有"造舟为梁，不显其光"的记载，描述周文王在渭河上架设浮桥的场景。春秋时期，齐国在淄水上架设了著名的"淄桥"，是中国历史上有明确记载的最早桥梁之一。</p>
      <h4>秦汉时期：桥梁技术的发展</h4>
      <p>秦汉时期桥梁建设得到大规模发展，栈道、飞桥、石拱桥开始出现。秦始皇统一六国后，修建了以咸阳为中心的全国道路网，著名的秦直道沿途修建了大量桥梁。汉代已能建造跨度达10米以上的石拱桥，著名的"灞桥"就是汉代的杰作。张骞出使西域时，丝绸之路沿途的桥梁发挥了重要作用。</p>
      <h4>唐宋时期：桥梁建设的鼎盛</h4>
      <p>唐宋是中国古代桥梁发展的黄金时期，涌现出赵州桥、洛阳桥、卢沟桥等传世杰作。唐代桥梁以宏大著称，宋代桥梁则在结构和装饰上达到顶峰。《清明上河图》中描绘的汴河虹桥就是当时桥梁技术的生动写照。宋代还出现了著名的"泉州石桥群"，包括洛阳桥、安平桥等。</p>
      <h4>元明清时期：桥梁的普及与完善</h4>
      <p>元明清时期桥梁建设更加普及，各地修建了大量石桥、木桥和廊桥。江南地区的水乡桥梁尤为发达，形成了独特的桥梁文化景观。清代皇家园林如颐和园、圆明园中也建造了大量精美桥梁，如颐和园的十七孔桥、玉带桥等。</p>
      <h4>近现代桥梁的发展</h4>
      <p>近代以来，中国桥梁建设吸收了西方技术，建造了许多现代化桥梁。武汉长江大桥是中国第一座跨越长江的公路铁路两用桥，于1957年建成通车，标志着中国桥梁建设进入了一个新阶段。</p>
    `},{id:3,title:"桥梁与交通网络",icon:"路",summary:"桥梁连接驿道与水运，是大一统帝国交通体系的关键节点。",detail:`
      <h4>驿道与桥梁</h4>
      <p>古代驿道系统遍布全国，桥梁是驿道的重要组成部分。著名的丝绸之路、茶马古道上都有大量桥梁，保障了驿传和商旅的通行。唐代驿站系统发达，每30里设一驿，重要河流上都建有桥梁。著名的"阳关大道"沿途就有许多桥梁，成为西域与中原交流的重要通道。</p>
      <h4>运河与桥梁</h4>
      <p>京杭大运河贯穿南北，沿线修建了众多桥梁。这些桥梁不仅连接了运河两岸，也成为运河文化的重要标志。如江苏苏州的宝带桥，始建于唐代，全长317米，是运河上的重要通道。杭州的拱宸桥是大运河的标志性桥梁，见证了运河的繁荣。</p>
      <h4>桥梁与城市发展</h4>
      <p>许多城市因桥而兴，桥梁成为城市的标志性建筑。苏州有"东方威尼斯"之称，城内桥梁众多，枫桥、宝带桥等都具有重要历史价值。扬州的二十四桥、杭州的断桥等都因文学作品而闻名天下。北京的颐和园十七孔桥是皇家园林桥梁的典范。</p>
      <h4>桥梁与军事防御</h4>
      <p>桥梁在军事防御中也发挥着重要作用。著名的"泸定桥"因红军长征中的"飞夺泸定桥"战役而闻名，成为革命历史的重要见证。许多古桥在历史上都曾作为军事要塞，具有重要的战略意义。</p>
    `},{id:4,title:"桥梁文学与艺术",icon:"文",summary:"诗词、绘画与题刻中的桥，是文人寄情山水的重要意象。",detail:`
      <h4>诗词中的桥梁</h4>
      <p>张继《枫桥夜泊》："月落乌啼霜满天，江枫渔火对愁眠。姑苏城外寒山寺，夜半钟声到客船。"此诗使枫桥名扬天下，成为苏州的文化符号。杜牧《寄扬州韩绰判官》："二十四桥明月夜，玉人何处教吹箫。"描绘了扬州的月夜美景，二十四桥因此成为扬州的象征。</p>
      <p>马致远《天净沙·秋思》："枯藤老树昏鸦，小桥流水人家，古道西风瘦马。"小桥成为中国古典诗词中表达乡愁的经典意象。李白《望天门山》："天门中断楚江开，碧水东流至此回。两岸青山相对出，孤帆一片日边来。"描绘了长江天险与桥梁的壮丽景象。</p>
      <p>温庭筠《商山早行》："鸡声茅店月，人迹板桥霜。"描绘了旅人清晨过桥的景象，成为唐诗中的经典名句。陆游《沈园二首》："伤心桥下春波绿，曾是惊鸿照影来。"以桥为背景表达了对逝去爱人的怀念。</p>
      <h4>绘画中的桥梁</h4>
      <p>中国传统绘画中常有桥梁元素，如张择端《清明上河图》中就描绘了汴河上的虹桥，展现了北宋都城的繁华景象。王希孟《千里江山图》中也绘有多处桥梁，与山水相映成趣。山水画中，桥梁常作为点缀，增添画面的意境美。</p>
      <p>清代画家石涛、八大山人等都在作品中描绘过桥梁，将其作为表达意境的重要元素。现代画家吴冠中也创作了许多以桥梁为主题的画作，展现了桥梁的形式美。</p>
      <h4>桥梁题刻</h4>
      <p>许多古桥上留有文人墨客的题刻和碑记，记录了桥梁的历史和建造过程，具有重要的历史价值和艺术价值。如赵州桥的"安济桥铭"由唐代文学家张鷟撰写，洛阳桥的"万安桥记"由宋代书法家蔡襄书写，都是书法艺术的珍品。</p>
      <p>卢沟桥的碑亭内保存着乾隆皇帝御笔题写的"卢沟晓月"碑，书法苍劲有力，是清代书法的代表作之一。</p>
    `},{id:5,title:"桥梁民俗文化",icon:"俗",summary:"节庆、信仰与地方习俗，赋予古桥超越交通的文化生命。",detail:`
      <h4>桥梁祭祀</h4>
      <p>许多地方有祭祀桥神的习俗，认为桥梁有神灵守护。福建地区有"桥祭"仪式，每年定期举行祭祀活动。江南水乡有"走桥"习俗，认为走过三座桥梁可以消灾祈福。浙江地区有"过桥会"，是当地重要的民俗活动。</p>
      <h4>节庆活动</h4>
      <p>一些桥梁成为节庆活动的场所，如北京卢沟桥的"卢沟晓月"是著名的燕京八景之一，吸引了众多游客前来观赏。有些地方在元宵节有"走百病"的习俗，妇女们会走过桥梁以祈求健康。杭州西湖的断桥在春节期间会举办各种文化活动。</p>
      <h4>桥梁传说</h4>
      <p>许多古桥都有美丽的传说，如西湖断桥的白娘子与许仙的爱情故事、赵州桥的鲁班修桥传说、泸定桥的红军飞夺泸定桥故事等，为桥梁增添了神秘色彩和历史厚重感。北京颐和园的十七孔桥也有关于"金光穿洞"的美丽传说。</p>
      <h4>桥梁命名文化</h4>
      <p>桥梁命名反映了丰富的文化内涵，或以地理位置命名（如赵州桥、洛阳桥），或以历史事件命名（如卢沟桥），或以形态特征命名（如五亭桥、风雨桥），或以吉祥寓意命名（如永济桥、太平桥）。还有以人名命名的桥梁，如苏州的"吴门桥"。</p>
      <h4>桥梁与民间艺术</h4>
      <p>桥梁也是民间艺术的重要题材，许多地方的民歌、戏曲、民间故事中都有桥梁的元素。如福建的梨园戏、浙江的越剧等都有以桥梁为背景的剧目。</p>
    `},{id:6,title:"桥梁文化传承",icon:"传",summary:"保护、研究与当代阐释，让古桥技艺在新时代延续。",detail:`
      <h4>古桥保护</h4>
      <p>中国政府高度重视古桥保护，许多著名古桥被列入全国重点文物保护单位。赵州桥、洛阳桥、卢沟桥、安平桥、广济桥等都得到了妥善的保护和修缮。近年来，越来越多的古桥被列入世界文化遗产预备名单。</p>
      <h4>学术研究</h4>
      <p>学术界对中国古代桥梁进行了深入研究，出版了大量专著和论文。茅以升先生的《中国古桥技术史》是桥梁史研究的经典著作。中国桥梁学会等学术团体定期举办学术研讨会，推动桥梁文化研究。</p>
      <h4>当代传承</h4>
      <p>传统桥梁建造技艺被列入非物质文化遗产名录，得到传承和发扬。许多地方建立了桥梁博物馆和展示中心，向公众普及桥梁文化知识。现代桥梁建设中也借鉴了古代桥梁的智慧，实现了传统与现代的完美结合。</p>
      <h4>数字保护与展示</h4>
      <p>随着数字化技术的发展，许多古桥被进行三维扫描和数字化建模，建立了虚拟展示平台。这不仅有助于古桥的保护研究，也让更多人能够通过互联网欣赏到中国古代桥梁的魅力。</p>
      <h4>国际交流与影响</h4>
      <p>中国古代桥梁技术对世界桥梁发展产生了重要影响。赵州桥的敞肩拱结构被后来的桥梁工程师广泛借鉴。近年来，中国桥梁建设成就举世瞩目，港珠澳大桥等现代桥梁成为中国的新名片。</p>
    `}],d=h=>{t.value=h},i=()=>{t.value=null};return _(async()=>{o.bridges.length||await o.initialize()}),(h,$)=>(l(),m(M,{title:"桥梁文化介绍",subtitle:"探索中国古代桥梁的文化内涵与历史意义",full:"",flush:""},{default:f(()=>[e("div",B,[(l(),n(y,null,v(c,s=>e("article",{key:s.id,class:"category-item ui-panel",onClick:q=>d(s)},[e("span",L,p(s.icon),1),e("h3",null,p(s.title),1),e("p",null,p(s.summary),1),N],8,I)),64))]),t.value?(l(),n("div",{key:0,class:"culture-modal",onClick:C(i,["self"])},[e("div",V,[e("button",{type:"button",class:"close-btn","aria-label":"关闭",onClick:i},"×"),e("div",D,[e("span",E,p(t.value.icon),1),e("h3",null,p(t.value.title),1)]),e("div",{class:"modal-body",innerHTML:t.value.detail},null,8,H)])],8,P)):k("",!0)]),_:1}))}});const J=S(T,[["__scopeId","data-v-9817dcdf"]]);export{J as default};
